import React, { useEffect } from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import { getMe } from './store/slices/authSlice';
import './assets/styles/global.css';

import Login          from './pages/Login';
import Dashboard      from './pages/Dashboard';
import Products       from './pages/Products';
import StockAdjustment from './pages/StockAdjustment';
import LowStock       from './pages/LowStock';
import NewInvoice     from './pages/NewInvoice';
import Invoices       from './pages/Invoices';
import InvoiceDetail  from './pages/InvoiceDetail';
import PendingDues    from './pages/PendingDues';
import Customers      from './pages/Customers';
import SalesReport    from './pages/SalesReport';
import StockReport    from './pages/StockReport';
import Settings       from './pages/Settings';

function PrivateRoute({ children }) {
  const { token } = useSelector((s) => s.auth);
  return token ? children : <Navigate to="/login" replace />;
}

export default function App() {
  const dispatch = useDispatch();
  const { token } = useSelector((s) => s.auth);

  useEffect(() => { if (token) dispatch(getMe()); }, [token, dispatch]);

  return (
    <BrowserRouter>
      <Routes>
        <Route path="/login" element={<Login />} />
        <Route path="/" element={<Navigate to="/dashboard" replace />} />
        <Route path="/dashboard"          element={<PrivateRoute><Dashboard /></PrivateRoute>} />
        <Route path="/inventory"          element={<PrivateRoute><Products /></PrivateRoute>} />
        <Route path="/inventory/stock"    element={<PrivateRoute><StockAdjustment /></PrivateRoute>} />
        <Route path="/inventory/low-stock" element={<PrivateRoute><LowStock /></PrivateRoute>} />
        <Route path="/billing/new"        element={<PrivateRoute><NewInvoice /></PrivateRoute>} />
        <Route path="/billing/edit/:id"   element={<PrivateRoute><NewInvoice /></PrivateRoute>} />
        <Route path="/billing"            element={<PrivateRoute><Invoices /></PrivateRoute>} />
        <Route path="/billing/:id"        element={<PrivateRoute><InvoiceDetail /></PrivateRoute>} />
        <Route path="/billing/dues"       element={<PrivateRoute><PendingDues /></PrivateRoute>} />
        <Route path="/customers"          element={<PrivateRoute><Customers /></PrivateRoute>} />
        <Route path="/reports/sales"      element={<PrivateRoute><SalesReport /></PrivateRoute>} />
        <Route path="/reports/stock"      element={<PrivateRoute><StockReport /></PrivateRoute>} />
        <Route path="/settings"           element={<PrivateRoute><Settings /></PrivateRoute>} />
        <Route path="*" element={<Navigate to="/dashboard" replace />} />
      </Routes>
    </BrowserRouter>
  );
}
